// Verify Stripe webhook signature. The Stripe-Signature header is of the form:
//   t=<timestamp>,v1=<signature>[,v0=<deprecated>]
// signature = HMAC-SHA256(`${timestamp}.${payload}`, STRIPE_WEBHOOK_SECRET)
//
// We accept a 5-minute clock skew window. Reject anything older.

const crypto = require('crypto');

const secret = $env.STRIPE_WEBHOOK_SECRET;
if (!secret) throw new Error('STRIPE_WEBHOOK_SECRET env var not set on n8n host');

const headers = $input.first().json.headers || {};
const sigHeader = headers['stripe-signature'] || headers['Stripe-Signature'];
if (!sigHeader) throw new Error('Missing Stripe-Signature header');

const rawBody = $input.first().json.body;
const payload = typeof rawBody === 'string' ? rawBody : JSON.stringify(rawBody);

const parts = Object.fromEntries(sigHeader.split(',').map((p) => p.split('=')));
const t = parseInt(parts.t, 10);
const v1 = parts.v1;
if (!t || !v1) throw new Error('Malformed Stripe-Signature');

const nowSec = Math.floor(Date.now() / 1000);
if (Math.abs(nowSec - t) > 300) throw new Error('Stripe timestamp outside 5-minute window');

const signedPayload = `${t}.${payload}`;
const expected = crypto.createHmac('sha256', secret).update(signedPayload).digest('hex');

// Constant-time compare.
const a = Buffer.from(expected, 'hex');
const b = Buffer.from(v1, 'hex');
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
  throw new Error('Stripe signature mismatch');
}

const event = typeof rawBody === 'string' ? JSON.parse(rawBody) : rawBody;
return [{ json: event }];

// Extract the buyer's email + SKU list from the Stripe Checkout Session.
//
// The webhook event for checkout.session.completed does NOT inline line_items by default.
// We rely on Stripe's `metadata.sku` on the Product (set by our bulk-import-v1) AND on
// `customer_details.email` (always present once the session completes).
//
// If line_items aren't inlined (default), we fall back to a second fetch in a later node
// — but most setups configure Stripe to include line_items.data.price.product in expansion.
// For this v1 workflow we just tag with the customer:stripe bucket; SKU-level tagging
// is a Phase-2 enhancement once line_items expansion is enabled.

const event = $input.first().json;
const session = event.data && event.data.object;
if (!session) throw new Error('No session payload in event');

const email = (session.customer_details && session.customer_details.email)
  || session.customer_email
  || null;
if (!email) throw new Error('No email on session');

const skus = [];
const items = (session.line_items && session.line_items.data) || [];
for (const it of items) {
  const sku = it.price && it.price.product && it.price.product.metadata && it.price.product.metadata.sku;
  if (sku) skus.push(sku);
}

return [{
  json: {
    email,
    skus,
    sessionId: session.id,
    amountTotal: session.amount_total,
    currency: session.currency,
    receivedAt: new Date().toISOString(),
  },
}];
